internal static ETGOTMSalesFormLetterService newETGOTMSalesFormLetterFromStatus(DocumentStatus _documentStatus)
{
    ETGOTMSalesFormLetterService instance;
    SysPluginMetadataCollection metadataCollection = new SysPluginMetadataCollection();

    metadataCollection.SetManagedValue(
        enumstr(DocumentStatus),
        enum2Symbol(enumNum(DocumentStatus), any2Enum(_documentStatus)));

    instance = SysPluginFactory::Instance(
        identifierStr(Dynamics.AX.Application),
        classStr(ETGOTMSalesFormLetterService),
        metadataCollection) as ETGOTMSalesFormLetterService;

    if (!instance)
    {
        throw error(Error::wrongUseOfFunction(funcName()));
    }

    return instance;
}
